SELECT COUNT(*) AS calibration_count
FROM calibration_data
WHERE sensor_id = 1;

SELECT sensor_id, MAX(calibration_date) AS latest_calibration_date
FROM calibration_data
GROUP BY sensor_id;

SELECT sensor_id 
FROM sensors 
WHERE status = 'active';

SELECT last_inspection_date
  FROM locations
  WHERE location_id = 1;

SELECT MAX(data_value) AS max_ph_value
FROM water_quality_data
WHERE location_id = 1 AND data_type = 'pH';
